head.script:
scwin.memJson = $c.data.getMemInfo();
scwin.userId = scwin.memJson.userId;
scwin.lobranCd = scwin.memJson.lobranCd;// 점소명
scwin.vCurDate = $c.date.getServerDateTime();

scwin.wrkLobranCd = scwin.lobranCd; // "<%=lobranCd%>"
scwin.min_step = 0;
scwin.max_step = 0;
scwin.v_last_rail1 = 0;
scwin.v_last_rail2 = 0;
scwin.v_last_rail3 = 0;
scwin.v_last_rail4 = 0;
scwin.currentDate; // 계산된 날
scwin.org_check_point = 0;
scwin.org2_check_point = 0;
scwin.rail_yn = "";
scwin.v_odrWrkStpSeq = 0;
scwin.v_odrWrkStpSeqMax = 0;

// hidden
scwin.hid_odrKndCd = ""; //  오더종류코드
scwin.hid_ctrtClntNo = ""; //  계약거래처
scwin.hid_ctrtNo = ""; //  계약번호
scwin.hid_realMchtclntNo = ""; //  실화주 거래처

scwin.hid_chkUseFilter = ""; //  필터 적용 여부 확인
scwin.hid_chkUseFilter2 = ""; //  필터 적용 여부 확인
scwin.hid_chkUseFilter3 = ""; //  필터 적용 여부 확인
scwin.hid_chkUseFilter4 = ""; //  필터 적용 여부 확인
scwin.oldValue = "";

scwin.onpageload = function () {
    scwin.odrNo = $c.data.getParameter("odrNo") == null ? "" : $c.data.getParameter("odrNo");
    scwin.odr_no_org = scwin.odrNo;
    const codeOptions = [
        { grpCd: "SD113", compID: "lc_odrKndCd"}    // 오더종류
    ];

    $c.data.setCommonCode(codeOptions);
};

// UDC에 값 세팅 방법
// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function () {
    ed_odrNo.show(); // cf_ShowObject([lay_odrDt]); // 오더기간 조회조건
    udc_fromToCalendar1.hide(); // 출발일자 조회조건 // lay_odrNo -> udc_fromToCalendar1
};

scwin.ondataload = function() { 
    let dlt = $c.gus.object("dlt_commonCodeSD113");
    $c.data.dataListFilter(dlt, "fltrCd1 == 'C' && fltrCd3 == '1'");

    // 초기화
    scwin.f_defaultValue();
    scwin.f_defaultHeader();

    //작업단계 LookUp DataSet Setting
    scwin.f_LkStepNo();
    scwin.f_wrkPlClsCd();

    if (!$c.gus.cfIsNull(scwin.odr_no_org)) {
        lc_odrSearchGubun.setValue(1);    // 조회 조건 (오더기간)
        ed_odrNo.setValue(scwin.odr_no_org);
        scwin.f_Retrieve();
    } else {
        ed_reqFromDt.setValue(scwin.vCurDate) // "<%= vCurDate %>";  // 조회기준일
        ed_reqToDt.setValue(scwin.vCurDate) // "<%= vCurDate %>";  // 조회기준일
        lc_odrSearchGubun.setValue(1);    // 조회 조건 (오더기간)
        lc_odrKndCd.setValue(0);
    }
}   

scwin.f_defaultHeader = function () {
    // DataSet Header 초기화
    $c.gus.cfDisableBtnOnly([btn_save]);
    $c.gus.cfEnableBtnOnly([btn_edit]); // btn_update -> btn_edit
}

//-------------------------------------------------------------------------
// 초기값 설정
//-------------------------------------------------------------------------
scwin.f_defaultValue = async function () {
    // DataSet Header 초기화
    // 조회 DataSet 초기화
    ds_orderSearch.set("odrNo", "");
    //컨테이너 Full/Empty
    // ds_cntrFE.DataID = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP171";

    dma_cntrFE.set("grpCd", "OP171")
    await $c.sbm.execute(sbm_cntrFE); // ds_cntrFE.Reset();
    let rowCnt = ds_odrCntrWrkPath.getRowCount();
    totalRows.setValue(rowCnt);
    ed_odrNo.focus();
}

// function f_Retrieve()
scwin.f_Retrieve = async function () {
    scwin.rail_yn = "";
    scwin.v_odrWrkStpSeq = 0;
    scwin.v_odrWrkStpSeqMax = 0;

    let odrSearchGubun = lc_odrSearchGubun.getValue();
    let odrNo = ed_odrNo.getValue().replace(/\s*$/, '');

    if (odrSearchGubun == "1") {
        if (odrNo == "") {
            await $c.win.alert("오더번호나 컨테이너 번호를 입력하세요.");
            return;
        }
    }

    if (odrSearchGubun == 0) {
        $c.gus.cfInitObjects(ed_odrNo);
        ds_orderSearch.set("odrNo", null);
        ds_orderSearch.set("odrDtFrom", ed_reqFromDt.getValue());
        ds_orderSearch.set("odrDtTo", ed_reqToDt.getValue());
    } else {
        odrNo = ed_odrNo.getValue().replace(/\s*$/, '');
        ds_orderSearch.set("odrNo", odrNo);
        ds_orderSearch.set("odrDtFrom", "");
        ds_orderSearch.set("odrDtTo", "");
    }


    ds_order.removeAll()
    ds_ctrtWrkPath.removeAll();
    ds_odrCntrWrkPath.removeAll();
    ds_odrWrkPathStep.removeAll();
    ds_ctrtWrkPathStep.removeAll();
    ds_odrWrkPathStepDetail.removeAll();

    let e = await $c.sbm.execute(sbm_retrieve); // tr_retrieve.post();
    scwin.sbm_retrieve_submitdone(e);

    scwin.org2_check_point = 0;
    for (let i = 0; i < ds_odrCntrWrkPath.getRowCount(); i++) {
        if (ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "chk") == "1") {
            scwin.org2_check_point = scwin.org2_check_point + 1;
        }
    }
    // 작업장구분 Lokkup DataSet Setting

    $c.gus.cfDisableBtnOnly([btn_save]);
    ds_searchWrkStep.set("odrNo", ed_odrNo.getValue());
    ds_searchWrkStep.set("cntrNo", ed_cntrNo.getValue());

    scwin.f_RetrieveWorkStepAll();

    $c.gus.cfDisableBtnOnly([btn_save]);
    $c.gus.cfEnableBtnOnly([btn_edit]); // btn_update -> btn_edit

    scwin.ds_LkStepNo_OnFilter();
    scwin.gr_odrWrkPathStepDetail_setGridReadOnly(true); // Editable = false;
}

scwin.gr_odrWrkPathStepDetail_setGridReadOnly = function(status) {
    gr_odrWrkPathStepDetail.setReadOnly(status);
}

scwin.f_filter = async function () {
    let ret = await $c.gus.cfValidate([ed_odrNo2])

    if (ret) {
        let odrNo = ed_odrNo2.getValue().replace(/\s*$/, '');
        ds_orderSearch2.set("odrNo", odrNo);
        ds_orderSearch2.set("cntrNo", ed_cntrNo2.getValue());
        ds_orderSearch2.set("dptWrkPlCd", ed_dptwrkPlCd1.getValue());
        ds_orderSearch2.set("arvWrkPlCd", ed_arvwrkPlCd1.getValue());
        $c.sbm.execute(sbm_retrieve2); // tr_retrieve2.post();
    }
}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    scwin.gr_odrWrkPathStepDetail_setGridReadOnly(false); // Editable = true;
    $c.gus.cfDisableBtnOnly([btn_edit]);
    $c.gus.cfEnableBtnOnly([btn_save]);
    gr_odrCntrWrkPath.focus();
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    let wrkLobranCd = "";
    let wrkLobranNm = "";
    let selpchItemCd = "";
    let dptWrkPlCd = "";
    let dptWrkPlNm = "";
    let arvWrkPlCd = "";
    let arvWrkPlNm = "";
    let dptWrkPlCdpre = "";
    let v_siljuk = 0;
    let v_silRow = 0;

    // 작업단계 정보 설정확인
    if (ds_odrWrkPathStepTemplete.getRowCount() == 0) {
        for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
            if (ds_odrWrkPathStepDetail.getRowStatus(i) != "D") { // RowStatus 가 Delete 가 아닌 경우
                // 작업구분이 지정되지 않은 경우(운송) 이전 단계의 작업장을 출발작업장으로, 다음 단계의 작업장을 도착작업장으로 설정한다.
                // 작업점소가 설정되지 않은 경우 작업점소는 이전 작업단계의 작업 점소를 설정한다.

                //여기는 운송모드로 본다
                if (($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))
                    || ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim() == "")
                    && i > 0) {

                    // 작업 점소
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkLobranCd"))
                        && ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)


                        ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranCd", wrkLobranCd);

                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkLobranNm"))
                        && ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)

                        ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranNm", wrkLobranNm);

                    // 작업장
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd"))
                        || ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd") == "") {


                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", dptWrkPlCd);
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", dptWrkPlNm);
                        ds_odrWrkPathStepTemplete.removeAll();
                        $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);
                    }

                    //삭제시 다음 작업노드의 dptWrkPlCd를 읽어 arvWrkPlCd에 셋팅한다.
                    for (let j = i; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
                        if (ds_odrWrkPathStepDetail.getRowStatus(j) != "D") {  // RowStatus 가 Delete 가 아닌 경우
                            if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim() != "" && j > i) {
                                if (dptWrkPlCdpre == "") {
                                    dptWrkPlCdpre = ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd");
                                }
                            }
                        }
                    }

                    ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", dptWrkPlCdpre);
                    dptWrkPlCdpre = "";

                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlNm"))){
                        var arvWrkPlNmVal = ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlNm")
                        ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlNm", arvWrkPlNmVal);
                    }
                    // 매출귀속부서
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "internalSellLodeptCd")) && ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") != "0000"){
                        var internalSellLodeptCdVal = ds_odrWrkPathStepDetail.getCellData(i - 1, "internalSellLodeptCd")
                        ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptCd", internalSellLodeptCdVal);
                    }
                    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "internalSellLodeptNm")) && ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") != "0000" && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "internalSellLodeptNm"))){
                        var internalSellLodeptNmVal = ds_odrWrkPathStepDetail.getCellData(i - 1, "internalSellLodeptNm");
                        ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNm", internalSellLodeptNmVal);
                    }


                    //여기는 작업노드로 본다
                } else if (ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim() != "" && i > 1) {
                    //작업장

                    if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd")) || ds_odrWrkPathStepDetail.getCellData(i - 1, "arvWrkPlCd") != "") {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", arvWrkPlCd);
                    } else {
                        ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", dptWrkPlCd);
                    }
                }
                wrkLobranCd = ds_odrWrkPathStepDetail.getCellData(i, "wrkLobranCd");
                wrkLobranNm = ds_odrWrkPathStepDetail.getCellData(i, "wrkLobranNm");
                dptWrkPlCd = ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd");
                arvWrkPlCd = ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlCd");
                dptWrkPlNm = ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlNm");
            }

            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo"))) { //
                v_siljuk = ds_odrWrkPathStepDetail.getCellData(i, "odrWrkStpSeq");
                v_silRow = i;
            }

            if (i == ds_odrWrkPathStepDetail.getRowCount()-1) {
                ds_odrWrkPathStepTemplete.removeAll()
                $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);
            }
        }//for

    } //if

    // 현재 품명의 작업단계 정보의  Vaildation 을 검사한다.
    let ret1 = await $c.gus.cfValidate([gr_odrWrkPathStepDetail]);
    if (!ret1) {
        return;
    }

    // 필수 입력 확인

    for (let idx = 0; idx < ds_odrWrkPathStepDetail.getRowCount(); idx++) {
        if (ds_odrWrkPathStepDetail.getRowStatus(idx) != "D") {    // RowStatus 가 Delete 가 아닌 경우

            // 작업장 확인 - 작업구분이 운송이 아닌 경우 작업장은 필수 입력 항목입니다.
            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkPlClsCd").trim()) && $c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "dptWrkPlCd").trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업장"));
                gr_odrWrkPathStepDetail.focus();
                gr_odrWrkPathStepDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowPosition(), 'dptWrkPlNm'); // SetColumn
                return false;
            }

            // 매출입항목이 무매출이 아니경우에는 작업점소, 매출귀속부서는 필수 입력항목입니다.
            if (ds_odrWrkPathStepDetail.getCellData(idx, "selpchItemCd") != "0000") {
                // 작업점소 확인
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkLobranCd").trim())) {
                    await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업점소"));
                    gr_odrWrkPathStepDetail.focus();
                    gr_odrWrkPathStepDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowPosition(), 'wrkLobranNm'); // SetColumn
                    return false;
                }

                //매출귀속부서 확인
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "internalSellLodeptCd").trim())) {
                    await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("매출귀속부서"));
                    gr_odrWrkPathStepDetail.focus();
                    gr_odrWrkPathStepDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowPosition(), 'internalSellLodeptNm'); // SetColumn
                    return false;
                }
            } else if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkPlClsCd").trim())) {
                // 작업점소 확인
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkLobranCd").trim())) {
                    await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업점소"));
                    gr_odrWrkPathStepDetail.focus();
                    gr_odrWrkPathStepDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowPosition(), 'wrkLobranNm'); // SetColumn
                    return false;
                }

                //매출귀속부서 확인
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "internalSellLodeptCd").trim())) {
                    await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("매출귀속부서"));
                    gr_odrWrkPathStepDetail.focus();
                    gr_odrWrkPathStepDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowPosition(), 'internalSellLodeptNm'); // SetColumn
                    return false;
                }
            }
        }
    }

    // 경로는 CHECK 된거만 보내주도록 한다. alert("bb::"+ds_odrWrkPathStepDetail.ExportData(1,ds_odrWrkPathStepDetail.getRowCount(),true));
    ds_odrWrkPathStepTemplete.removeAll();
    $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);


    if ($c.gus.cfIsNull(ds_odrCntrWrkPathTemplete.getCellData(0, "odrNo"))) {
        ds_odrCntrWrkPathTemplete.removeAll();
        ds_odrCntrWrkPathTemplete.insertRow();
        let rowData = ds_odrCntrWrkPath.getRowJSON(ds_odrCntrWrkPath.getRowPosition());

        ds_odrCntrWrkPathTemplete.setCellData(0, "odrNo", rowData["odrNo"]);
        ds_odrCntrWrkPathTemplete.setCellData(0, "cntrSeq", rowData["cntrSeq"]);
        ds_odrCntrWrkPathTemplete.setCellData(0, "odrWrkPathSeq", rowData["odrWrkPathSeq"]);
        ds_odrCntrWrkPathTemplete.setCellData(0, "ctrtNo", rowData["ctrtNo"]);
        ds_odrCntrWrkPathTemplete.setCellData(0, "ctrtWrkPathSeq", rowData["ctrtWrkPathSeq"]);
        ds_odrCntrWrkPathTemplete.setCellData(0, "dptWrkPlCd", rowData["dptWrkPlCd"]);
        ds_odrCntrWrkPathTemplete.setCellData(0, "arvWrkPlCd", rowData["arvWrkPlCd"]);
    }

    ds_odrCntrWrkPathChg.removeAll();
    $c.gus.cfCopyDataSetHeader(ds_odrCntrWrkPath, ds_odrCntrWrkPathChg);

    for (let i = 0; i < ds_odrCntrWrkPath.getRowCount(); i++) {
        if (ds_odrCntrWrkPath.getCellData(i, "chk") != 0) {
            let j = ds_odrCntrWrkPathChg.insertRow();
            let rowData = ds_odrCntrWrkPath.getRowJSON(i);

            ds_odrCntrWrkPathChg.setCellData(j, "chk", rowData["chk"]);
            ds_odrCntrWrkPathChg.setCellData(j, "odrNo", rowData["odrNo"]);
            ds_odrCntrWrkPathChg.setCellData(j, "cntrSeq", rowData["cntrSeq"]);
            ds_odrCntrWrkPathChg.setCellData(j, "cntrNo", rowData["cntrNo"]);
            ds_odrCntrWrkPathChg.setCellData(j, "arrvlportDtm", rowData["arrvlportDtm"]);
            ds_odrCntrWrkPathChg.setCellData(j, "cntrSizCd", rowData["cntrSizCd"]);
            ds_odrCntrWrkPathChg.setCellData(j, "cntrTypCd", rowData["cntrTypCd"]);
            ds_odrCntrWrkPathChg.setCellData(j, "fullEmptyClsCd", rowData["fullEmptyClsCd"]);
            ds_odrCntrWrkPathChg.setCellData(j, "odrWrkPathSeq", rowData["odrWrkPathSeq"]);
            ds_odrCntrWrkPathChg.setCellData(j, "ctrtNo", rowData["ctrtNo"]);
            ds_odrCntrWrkPathChg.setCellData(j, "ctrtWrkPathSeq", rowData["ctrtWrkPathSeq"]);
            ds_odrCntrWrkPathChg.setCellData(j, "dptWrkPlClsCd", rowData["dptWrkPlClsCd"]);
            ds_odrCntrWrkPathChg.setCellData(j, "dptWrkPlCd", rowData["dptWrkPlCd"]);
            ds_odrCntrWrkPathChg.setCellData(j, "dptWrkPlNm", rowData["dptWrkPlNm"]);
            ds_odrCntrWrkPathChg.setCellData(j, "arvWrkPlClsCd", rowData["arvWrkPlClsCd"]);
            ds_odrCntrWrkPathChg.setCellData(j, "arvWrkPlCd", rowData["arvWrkPlCd"]);
            ds_odrCntrWrkPathChg.setCellData(j, "arvWrkPlNm", rowData["arvWrkPlNm"]);
            ds_odrCntrWrkPathChg.setCellData(j, "wrkStDt", rowData["wrkStDt"]);
            ds_odrCntrWrkPathChg.setCellData(j, "wrkStHh", rowData["wrkStHh"]);
            ds_odrCntrWrkPathChg.setCellData(j, "wrkEndDt", rowData["wrkEndDt"]);
            ds_odrCntrWrkPathChg.setCellData(j, "wrkEndHh", rowData["wrkEndHh"]);
            ds_odrCntrWrkPathChg.setCellData(j, "sellYn", rowData["sellYn"]);
            ds_odrCntrWrkPathChg.setCellData(j, "wrkRsltsNo", rowData["wrkRsltsNo"]);
        }
    }

    let check_su = 0;
    for (let i = 0; i < ds_odrCntrWrkPath.getRowCount(); i++) {
        if (ds_odrCntrWrkPath.getCellData(i, "chk") != 0) {
            check_su = check_su + 1;
        }
    }

    if (check_su == 0) {
        await $c.gus.cfAlertMsg("하나 이상 선택하셔야 합니다.");
        return false;
    }

    for (let i = 0; i < ds_odrWrkPathStepTemplete.getRowCount(); i++) {
        if (!$c.gus.cfIsNull(v_siljuk) && v_siljuk != 0 && (i <= v_silRow + 1)) {
            ds_odrWrkPathStepTemplete.setCellData(i, "transWrkIndictNo", 'K123');
        }
    }

    let validChk = scwin.f_validChk();
    if (validChk) {
        if (await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_001, new Array("작업단계정보")))) {
            $c.sbm.execute(sbm_save); // tr_save.Post();
        } else {
            // gr_odrCntrWrkPath.DataID = "ds_odrCntrWrkPath";
            // gr_odrWrkPathStepDetail.DataID = "ds_odrWrkPathStepDetail";
        }
    }
}

