//---------------------------------------------------------------------------------
// 선택된 그리드에 작업단계 삽입 : 첫번째열을 선택한 경우 해당열 아래에 행삽입 후 이전 작업단계 정보 복사
//---------------------------------------------------------------------------------
scwin.f_InsertRow = async function () {
    let rowPos = ds_odrWrkPathStepDetail.getRowPosition();
    let startIdx = (rowPos == null || rowPos < 0) ? 0 : rowPos;
    let rowCount = ds_odrWrkPathStepDetail.getRowCount();
    let loopEnd = (rowCount === 0) ? 1 : rowCount;

    //현행포함 이후의 행들에 작업지시나 실적이 있을시 행을 삽입할 수 없다.
    for (let i = startIdx; i < loopEnd; i++) {
        let transRsltsSeq, transWrkIndictNo;

        if (rowCount === 0) {
            transRsltsSeq = undefined;
            transWrkIndictNo = undefined;
        } else {
            transRsltsSeq = ds_odrWrkPathStepDetail.getCellData(i, "transRsltsSeq");
            transWrkIndictNo = ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo");
        }

        if (transRsltsSeq > 0) {
            await $c.gus.cfAlertMsg("삽입하고자 하는 이후의 작업단계에 운송실적이 발생되어서 삽입할 수 없습니다.");
            return;
        } else if (transWrkIndictNo != "") {
            await $c.gus.cfAlertMsg("삽입하고자 하는 이후의 작업단계에 운송작업지시가 발생되어서 삽입할 수 없습니다.");
            return;
        }
    }
    if (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkStpSeq") % 10 < 9) {
        // 선택된 행 아래에 새로운 행 삽입
        let newRow = ds_odrWrkPathStepDetail.insertRow(ds_odrWrkPathStepDetail.getRowPosition() + 1);
        gr_odrWrkPathStepDetail.setFocusedCell(newRow, "odrWrkStpSeq");
        scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, ds_odrWrkPathStepDetail.getRowPosition() - 1, ds_odrWrkPathStepDetail.getRowPosition());

    } else {
        await $c.gus.cfAlertMsg("더이상 작업단계를 추가할수 없습니다."); //작업단계을(를) 확인하여 주십시오
        return;
    }
}


