    scwin.applyRowColor();
}

//-------------------------------------------------------------------------
// 선택된 그리드에 작업단계 삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = async function () {
    //현행포함 이후의 행들에 작업지시나 실적이 있을시 행을 삭제할 수 없다.
    let rowPos = ds_odrWrkPathStepDetail.getRowPosition();
    let startIdx = (rowPos == null || rowPos < 0) ? 0 : rowPos;
    let rowCount = ds_odrWrkPathStepDetail.getRowCount();
    let loopEnd = (rowCount === 0) ? 1 : rowCount;

    for (let i = startIdx; i < loopEnd; i++) {
        let transRsltsSeq, transWrkIndictNo;
        if (rowCount === 0) {
            transRsltsSeq = undefined;
            transWrkIndictNo = undefined;
        } else {
            transRsltsSeq = ds_odrWrkPathStepDetail.getCellData(i, "transRsltsSeq");
            transWrkIndictNo = ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo");
        }

        if (transRsltsSeq > 0) {
            await $c.gus.cfAlertMsg("삭제하고자 하는 이후의 작업단계에 운송실적이 발생되어서 삭제할 수 없습니다.");
            return;
        }
        if (i - 1 > 0) {
            if (transRsltsSeq > 0) {
                await $c.gus.cfAlertMsg("삭제하고자 하는 단계가 포함된 운송작업단계에 운송실적이 발생되어서 삭제할 수 없습니다.");
                return;
            }
        }
        if (transWrkIndictNo != "") {
            await $c.gus.cfAlertMsg("삭제하고자 하는 이후의 작업단계에 운송작업지시가 발생되어서 삭제할 수 없습니다.");
            return;
        }
        if (i - 1 > 0) {
            if (transWrkIndictNo != "") {
                await $c.gus.cfAlertMsg("삭제하고자 하는 단계가 포함된 운송작업단계에 운송작업지시가 발생되어서 삭제할 수 없습니다.");
                return;
            }
        }
    } //end of for(i)

    for (let i = ds_odrWrkPathStepDetail.getRowCount()-1; i >= 0; i--) {
        let targetRow = gr_odrWrkPathStepDetail.getFocusedRowIndex();
        if (i == targetRow) {
            if (ds_odrWrkPathStepDetail.getCellData(i, "transRsltsSeq") > 0) {
                await $c.gus.cfAlertMsg("삭제하고자 하는 이후의 작업단계에 운송실적이 발생되어서 삭제할 수 없습니다.");
                return;
            }
            if (i - 1 > 0) {
                if (ds_odrWrkPathStepDetail.getCellData(i - 1, "transRsltsSeq") > 0) {
                    await $c.gus.cfAlertMsg("삭제하고자 하는 단계가 포함된 운송작업단계에 운송실적이 발생되어서 삭제할 수 없습니다.");
                    return;
                }
            }
            if (ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo") != "") {
                await $c.gus.cfAlertMsg("삭제하고자 하는 이후의 작업단계에 운송작업지시가 발생되어서 삭제할 수 없습니다.");
                return;
            }
            if (i - 1 > 0) {
                if (ds_odrWrkPathStepDetail.getCellData(i - 1, "transWrkIndictNo") != "") {
                    await $c.gus.cfAlertMsg("삭제하고자 하는 단계가 포함된 운송작업단계에 운송작업지시가 발생되어서 삭제할 수 없습니다.");
                    return;
                }
            }
            if (i == targetRow) {
                ds_odrWrkPathStep.setCellData(i, "transWrkIndictNo", "Y");
                ds_odrWrkPathStepDetail.removeRow(i);
                //ds_odrWrkPathStepTemplete.deleteRow(i);
            }
        }
    }

    scwin.org_check_point = 0;
    ds_odrWrkPathStepTemplete.removeAll();
    $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);

    for (let j = 0; j < ds_odrWrkPathStepTemplete.getRowCount(); j++) {
        if (!$c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(j, "transWrkIndictNo"))) {
            scwin.org_check_point = scwin.org_check_point + 1;
        }
    }

    let apendcount = 0;
    //ds_odrWrkPathStep    ds_odrWrkPathStepTemplete
    for (let j = 0; j < ds_odrWrkPathStep.getRowCount(); j++) {
        apendcount = 0;
        for (let i = 0; i < ds_odrWrkPathStepTemplete.getRowCount(); i++) {

            if (ds_odrWrkPathStepTemplete.getCellData(i, "odrWrkStpSeq") == ds_odrWrkPathStep.getCellData(j, "odrWrkStpSeq")) {
                apendcount = apendcount + 1;
            }
        }
        if (apendcount == 0) {
            let newRow = ds_odrWrkPathStepTemplete.insertRow();

            ds_odrWrkPathStepTemplete.setCellData(newRow, "odrNo", ds_odrWrkPathStep.getCellData(j, "odrNo"));
            ds_odrWrkPathStepTemplete.setCellData(newRow, "cntrSeq",ds_odrWrkPathStep.getCellData(j, "cntrSeq"));
            ds_odrWrkPathStepTemplete.setCellData(newRow, "odrWrkPathSeq", ds_odrWrkPathStep.getCellData(j, "odrWrkPathSeq"));
            ds_odrWrkPathStepTemplete.setCellData(newRow, "odrWrkStpSeq",ds_odrWrkPathStep.getCellData(j, "odrWrkStpSeq"));
            ds_odrWrkPathStepTemplete.setCellData(newRow, "transWrkIndictNo", ds_odrWrkPathStep.getCellData(j, "transWrkIndictNo"));
        }
    }
    //작업단계정렬
    scwin.f_SortRow();

    //여기다 경로 체크를 해준다.

    let rowVal = ds_odrCntrWrkPath.getRowPosition();
    ds_odrCntrWrkPath.setCellData(rowVal, "chk", 1);
    ds_odrCntrWrkPathTemplete.removeAll();
    $c.gus.cfCopyDataSetHeader(ds_odrCntrWrkPath, ds_odrCntrWrkPathTemplete);
    let newRow = ds_odrCntrWrkPathTemplete.insertRow();

    ds_odrCntrWrkPathTemplete.setCellData(newRow, "odrNo",ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrNo"));
    ds_odrCntrWrkPathTemplete.setCellData(newRow, "cntrSeq",ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "cntrSeq"));
    ds_odrCntrWrkPathTemplete.setCellData(newRow, "odrWrkPathSeq", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrWrkPathSeq"));
    ds_odrCntrWrkPathTemplete.setCellData(newRow, "ctrtNo",ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtNo"));
    ds_odrCntrWrkPathTemplete.setCellData(newRow, "ctrtWrkPathSeq",ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtWrkPathSeq"));
    ds_odrCntrWrkPathTemplete.setCellData(newRow, "dptWrkPlCd", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "dptWrkPlCd"));
    ds_odrCntrWrkPathTemplete.setCellData(newRow, "arvWrkPlCd", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "arvWrkPlCd"));

}

scwin.f_SortRow = function () {
    let wrkLobranCd = "";
    let wrkLobranNm = "";
    let selpchItemCd = "";
    let dptWrkPlCd = "";
    let dptWrkPlNm = "";
    let arvWrkPlCd = "";
    let arvWrkPlNm = "";
    let dptWrkPlCdpre = "";
    let v_siljuk = 0;
    let v_silRow = 0;

    for (let i = 0; i < ds_odrWrkPathStepTemplete.getRowCount(); i++) {
        if (ds_odrWrkPathStepTemplete.getRowStatus(i) != "D") {   // RowStatus 가 Delete 가 아닌 경우
            // 작업구분이 지정되지 않은 경우(운송) 이전 단계의 작업장을 출발작업장으로, 다음 단계의 작업장을 도착작업장으로 설정한다.
            // 작업점소가 설정되지 않은 경우 작업점소는 이전 작업단계의 작업 점소를 설정한다.

            //여기는 운송모드로 본다
            if (ds_odrWrkPathStepTemplete.getCellData(i, "wrkPlClsCd").trim() == "" && i > 0) {
                // 작업 점소
                if ($c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(i, "wrkLobranCd"))
                    && ds_odrWrkPathStepTemplete.getCellData(i, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)

                    ds_odrWrkPathStepTemplete.setCellData(i, "wrkLobranCd", wrkLobranCd);

                if ($c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(i, "wrkLobranNm"))
                    && ds_odrWrkPathStepTemplete.getCellData(i, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)

                    ds_odrWrkPathStepTemplete.setCellData(i, "wrkLobranNm", wrkLobranNm);

                // 작업장
                if ($c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(i, "dptWrkPlCd"))) {

                    ds_odrWrkPathStepTemplete.setCellData(i, "dptWrkPlCd", dptWrkPlCd);
                } else {
                    ds_odrWrkPathStepTemplete.setCellData(i, "dptWrkPlCd", dptWrkPlCd);
                }

                //삭제시 다음 작업노드의 dptWrkPlCd를 읽어 arvWrkPlCd에 셋팅한다.
                for (let j = i; j < ds_odrWrkPathStepTemplete.getRowCount(); j++) {
                    if (ds_odrWrkPathStepTemplete.getRowStatus(j) != "D") {    // RowStatus 가 Delete 가 아닌 경우
                        if (ds_odrWrkPathStepTemplete.getCellData(j, "wrkPlClsCd").trim() != "" && j > i) {
                            if (dptWrkPlCdpre == "") {
                                dptWrkPlCdpre = ds_odrWrkPathStepTemplete.getCellData(j, "dptWrkPlCd");
                            }
                        }
                    }
                }

                ds_odrWrkPathStepTemplete.setCellData(i, "arvWrkPlCd", dptWrkPlCdpre);
                dptWrkPlCdpre = "";

                if ($c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(i, "arvWrkPlNm")))
                    ds_odrWrkPathStepTemplete.setCellData(i, "arvWrkPlNm", ds_odrWrkPathStepTemplete.getCellData(i + 1, "dptWrkPlNm"));

                // 매출귀속부서
                if ($c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(i, "internalSellLodeptCd")) && ds_odrWrkPathStepTemplete.getCellData(i, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL)
                    ds_odrWrkPathStepTemplete.setCellData(i, "internalSellLodeptCd", ds_odrWrkPathStepTemplete.getCellData(i - 1, "internalSellLodeptCd"))
                if ($c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(i, "internalSellLodeptNm"))
                    && ds_odrWrkPathStepTemplete.getCellData(i, "selpchItemCd") != SdConstants.SELPCH_ITEM_CD_NOSELL
                    && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "internalSellLodeptNm")))

                    ds_odrWrkPathStepTemplete.setCellData(i, "internalSellLodeptNm", ds_odrWrkPathStepTemplete.getCellData(i - 1, "internalSellLodeptNm"))

            } else if (ds_odrWrkPathStepTemplete.getCellData(i, "wrkPlClsCd").trim() != "" && i > 1) {
                //여기는 작업노드로 본다

                //작업장
                if (!$c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(i - 1, "arvWrkPlCd"))
                    || ds_odrWrkPathStepTemplete.getCellData(i - 1, "arvWrkPlCd") != "") {
                    ds_odrWrkPathStepTemplete.setCellData(i, "dptWrkPlCd", arvWrkPlCd);
                }
            }

            wrkLobranCd = ds_odrWrkPathStepTemplete.getCellData(i, "wrkLobranCd");
            wrkLobranNm = ds_odrWrkPathStepTemplete.getCellData(i, "wrkLobranNm");
            dptWrkPlCd = ds_odrWrkPathStepTemplete.getCellData(i, "dptWrkPlCd");
            arvWrkPlCd = ds_odrWrkPathStepTemplete.getCellData(i, "arvWrkPlCd");
            dptWrkPlNm = ds_odrWrkPathStepTemplete.getCellData(i, "dptWrkPlNm");
        }
        if (!$c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(i, "transWrkIndictNo"))) { //
            v_siljuk = ds_odrWrkPathStepTemplete.getCellData(i, "odrWrkStpSeq");
            v_silRow = i;
        }
    }
}



// to-do 이벤트 파라미터 담아서 오는지 확인 필요.
scwin.ln_LeftMove = async function (type) {
    let v_seq = 0;
    let v_max_seq = 0;
    let v_check = 0;
    let v_add = 0;
    let v_add2 = 0;
    let temp_max_step = 0;
    let v_flg = 0;
    let day = "";
    let Dday;
    let DHours;
    let DMinits;
    let nowwrkEndMh;
    v_seq = Number(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "odrWrkStpSeq"));
    v_max_seq = v_seq + 9;

    if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "odrWrkStpSeq"))) {
        v_check = 1;
    }

    for (i = 0; i < ds_ctrtWrkPathStpDetail.getRowCount(); i++) {
        let targetRow = gr_ctrtWrkPathStpDetail.getFocusedRowIndex();
        if ((type == 'm') && (i == targetRow)) {
            temp_max_step = scwin.max_step - 1;
            if (scwin.max_step != 0) {
                if (ds_odrWrkPathStepDetail.getRowPosition() <= temp_max_step) {
                    await $c.gus.cfAlertMsg("실적이 발생되지 않은 단계에서만 복사가 가능합니다.");
                    return;
                }
            }
            //운송모드 VS 작업노드
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkPlClsCd")) &&
                $c.gus.cfIsNull(ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd"))) {
                await $c.gus.cfAlertMsg("운송모드 다음에 운송모드를 추가할수 없습니다.!!!");
                return;
            }

            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkPlClsCd")) &&
                !$c.gus.cfIsNull(ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd"))) {
                if ((ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0029"
                    && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0028")
                    || (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0012"
                        && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0011")) {
                    //하차 다음에는 상차 올수 있다.
                    if (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkPlClsCd") != ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd")) {
                        await $c.gus.cfAlertMsg("복사하려는 상차단계의 작업장 구분이 하차단계의  작업장 구분과 동일하지 않습니다..!!!예)이전하차가  C 면  복사하려는 작업장 구분도 C 이어야 합니다.");
                        return;
                    }
                    if (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "dptWrkPlCd") != ds_ctrtWrkPathStpDetail.getCellData(i, "dptWrkPlCd")) {
                        await $c.gus.cfAlertMsg("복사하려는 상차단계의 작업장이 하차단계의 작업장과   동일하지 않습니다..!!!");
                        return;
                    }
                } else {
                    if ((ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0029"
                        && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") != "0028")
                        || (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0012"
                            && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") != "0011")) {
                        await $c.gus.cfAlertMsg("하차 다음에는 상차만 올수 있습니다..!!!");
                        return;
                    } else {
                        if ((ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0028"
                            && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0029")) {
                            await $c.win.alert("ok");
                        } else {
                            await $c.gus.cfAlertMsg("작업모드 다음에 작업모드를 추가할수 없습니다.!!!");
                            return;
                        }
                    }
                }
            }

            //여기서는 철송조작  다음에는 철송/셔틀만 올수 있습니다.
            if (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0046") {
                //첫번째 철송구간
                if (scwin.v_last_rail1 == ds_odrWrkPathStepDetail.getRowPosition()
                    && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") != "0004") {
                    await $c.gus.cfAlertMsg("첫번째 출발역 다음에는 철송만  올수 있습니다.!!!");
                    return;
                }
                if (scwin.v_last_rail2 == ds_odrWrkPathStepDetail.getRowPosition()
                    && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") != "0001") {
                    await $c.gus.cfAlertMsg("첫번째  도착역 다음에는 셔틀만  올수 있습니다.!!!");
                    return;
                }

                //두번째 철송구간
                if (scwin.v_last_rail3 != 0 && scwin.v_last_rail4 != 0) {
                    if (scwin.v_last_rail3 == ds_odrWrkPathStepDetail.getRowPosition()
                        && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") != "0004") {
                        await $c.gus.cfAlertMsg("두번째 출발역 다음에는 철송만  올수 있습니다.!!!");
                        return;
                    }
                    if (scwin.v_last_rail4 != ds_odrWrkPathStepDetail.getRowPosition()
                        && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") != "0001") {
                        await $c.gus.cfAlertMsg("두번째 도착역  다음에는 셔틀만 올수 있습니다.!!!");
                        return;
                    }
                }
                v_flg = 1;
            }
            if (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0011"
                || ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0028") {
                if (ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0001"
                    || ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0002"
                    || ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0047") {
                } else {
                    if ((ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0028"
                        && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0029")) {
                        await $c.win.alert("ok");
                    } else {
                        await $c.gus.cfAlertMsg("상차 다음에는 셔틀/육송/DOOR 운송만 올수 있습니다...!!!");
                        return;
                    }
                }
            }

            if (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0024"
                || ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkStpCd") == "0025") {
                if (ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0003") {
                    //$c.win.alert("ok~");
                } else {
                    await $c.gus.cfAlertMsg("DOOR 적입/적출 다음에는 DOOR 회수운송만 올수 있습니다...!!!");
                    return;
                }
            }
            //삽입하려는 단계 참조
            //운송모드 VS 작업노드
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "wrkPlClsCd"))
                && ds_odrWrkPathStepDetail.getRowPosition() != ds_odrWrkPathStepDetail.getRowCount()-1
                && $c.gus.cfIsNull(ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd"))) {
                await $c.gus.cfAlertMsg("기존에 존재하는  운송단계를 먼저 삭제하세요!!!");
                return;
            }

            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "wrkPlClsCd"))
                && ds_odrWrkPathStepDetail.getRowPosition() != ds_odrWrkPathStepDetail.getRowCount()-1
                && !$c.gus.cfIsNull(ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd"))) {
                if ((ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "wrkStpCd") == "0028"
                    && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0029")
                    || (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "wrkStpCd") == "0011"
                        && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") == "0012")) {
                    // 하차 이전에 상차 올수 있다.
                } else {
                    if ((ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "wrkStpCd") == "0028"
                        && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") != "0029")
                        || (ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition() + 1, "wrkStpCd") == "0011"
                            && ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd") != "0012")) {
                        await $c.gus.cfAlertMsg("상차 이전에는 하차만 올수 있습니다..!!!");
                        return;
                    } else {
                        await $c.gus.cfAlertMsg("작업모드 이전에 작업모드를 추가할수 없습니다.!!!");
                        return;
                    }
                }
            }

            //처리로직
            //seq 기존 작업단계에 +1
            v_add = v_add + 1;
            v_add2 = v_add2 + 10;


            if (v_check == 1) {

                let rowVal = ds_odrWrkPathStepDetail.getRowPosition();

                let newRow = ds_odrWrkPathStepDetail.insertRow(rowVal + 1);
                ds_odrWrkPathStepDetail.setCellData(newRow, "odrWrkStpSeq", v_seq + v_add2);
                ds_odrWrkPathStepDetail.setCellData(newRow, "odrNo", ds_odrWrkPathStepDetail.getCellData(rowVal, "odrNo"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "cntrSeq", ds_odrWrkPathStepDetail.getCellData(rowVal, "cntrSeq"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "odrWrkPathSeq", ds_odrWrkPathStepDetail.getCellData(rowVal, "odrWrkPathSeq"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "wrkPlClsCd", ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStpCd", ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "dptWrkPlCd", ds_ctrtWrkPathStpDetail.getCellData(i, "dptWrkPlCd"));
                if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(newRow, "wrkPlClsCd"))) {
                    ds_odrWrkPathStepDetail.setCellData(newRow, "dptWrkPlNm", ds_ctrtWrkPathStpDetail.getCellData(i, "dptWrkPlNm"));
                } else {
                    ds_odrWrkPathStepDetail.setCellData(newRow, "dptWrkPlNm", "");
                }
                ds_odrWrkPathStepDetail.setCellData(newRow, "arvWrkPlCd", ds_ctrtWrkPathStpDetail.getCellData(i, "arvWrkPlCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "arvWrkPlNm", ds_ctrtWrkPathStpDetail.getCellData(i, "arvWrkPlNm"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "selpchItemCd", ds_ctrtWrkPathStpDetail.getCellData(i, "selpchItemCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "selpchItemNm", ds_ctrtWrkPathStpDetail.getCellData(i, "selpchItemNm"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "wrkLobranCd", ds_ctrtWrkPathStpDetail.getCellData(i, "wrkLobranCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "wrkLobranNm", ds_ctrtWrkPathStpDetail.getCellData(i, "wrkLobranNm"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "internalSellLodeptCd", ds_ctrtWrkPathStpDetail.getCellData(i, "internalSellLodeptCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "internalSellLodeptNm", ds_ctrtWrkPathStpDetail.getCellData(i, "internalSellLodeptNm"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "fullEmptyClsCd", ds_ctrtWrkPathStpDetail.getCellData(i, "fullEmptyClsCd"));

                if (v_flg == 1) {
                    scwin.f_railstepDetail();
                }

                let prewrkStDt = ds_odrWrkPathStepDetail.getCellData(rowVal, "wrkStDt");
                let prewrkStHh = ds_odrWrkPathStepDetail.getCellData(rowVal, "wrkStHh");
                let prewrkEndDt = ds_odrWrkPathStepDetail.getCellData(rowVal, "wrkEndDt");
                let prewrkEndHh = ds_odrWrkPathStepDetail.getCellData(rowVal, "wrkEndHh");

                ////작업노드/운송모드,시간배분,(SD401도착일시=SD403도착일시)
                if ($c.gus.cfIsNull(ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd"))) {
                    //운송모드 //FROM
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStDt", prewrkEndDt);
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStHh", prewrkEndHh);
                    //TO
                    nowwrkEndMh = Number(prewrkEndHh.substring(0, 2)) * 60 + Number(prewrkEndHh.substring(2, 4)) + 60;
                    if (nowwrkEndMh >= 1440) {
                        Dday = 1;
                        DHours = "00";
                        DMinits = String(nowwrkEndMh - 1440);
                        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt",String(scwin.addDay(prewrkEndDt.substring(0, 4),prewrkEndDt.substring(4, 6),prewrkEndDt.substring(6, 8), Dday)));
                    } else {
                        Dday = 0;
                        DHours = String(Math.floor(nowwrkEndMh / 60));
                        DMinits = String(nowwrkEndMh % 60);
                        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt", prewrkEndDt);
                    }
                    if (Number(DHours) <= 9) {
                        DHours = "0" + String(Number(DHours));
                        if (parseInt(DMinits) <= 9) {
                            if (parseInt(DMinits) != 0) {
                                DMinits = "0" + String(parseInt(DMinits));
                            } else {
                                DMinits = "00";
                            }
                        }
                    } else {
                        if (parseInt(DMinits) <= 9) {
                            if (parseInt(DMinits) != 0) {
                                DMinits = "0" + String(parseInt(DMinits));
                            } else {
                                DMinits = "00";
                            }
                        }
                    }
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndHh", DHours + DMinits);

                } else {
                    //작업 노느 //FROM
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStDt", prewrkEndDt);
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStHh", prewrkEndHh);
                    //TO
                    nowwrkEndMh = Number(prewrkEndHh.substring(0, 2)) * 60 + Number(prewrkEndHh.substring(2, 4)) + 20;

                    if (nowwrkEndMh >= 1440) {
                        Dday = 1;
                        DHours = "00";
                        DMinits = String(nowwrkEndMh - 1440);
                        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt",String(scwin.addDay(prewrkEndDt.substring(0, 4), prewrkEndDt.substring(4, 6), prewrkEndDt.substring(6, 8), Dday)));
                    } else {
                        Dday = 0;
                        DHours = String(Math.floor(nowwrkEndMh / 60));
                        DMinits = String(nowwrkEndMh % 60);
                        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt", prewrkEndDt);
                    }
                    if (Number(DHours) <= 9) {
                        DHours = "0" + String(Number(DHours));
                        if (parseInt(DMinits) <= 9) {
                            if (parseInt(DMinits) != 0) {
                                DMinits = "0" + String(parseInt(DMinits));
                            } else {
                                DMinits = "00";
                            }
                        }
                    } else {
                        if (parseInt(DMinits) <= 9) {
                            if (parseInt(DMinits) != 0) {
                                DMinits = "0" + String(parseInt(DMinits));
                            } else {
                                DMinits = "00";
                            }
                        }
                    }
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndHh", DHours + DMinits);
                }

            } else {
                if ((v_max_seq < v_seq + v_add) && (v_check == 0)) {
                    await $c.gus.cfAlertMsg("마지막 작업단계가 아닌경우 즉 작업단계 사인경우에는  9단계이상 추가 할수 없습니다..!!!");
                    return;
                }
                //   구분/작업단계/작업장/작업점/매출부서

                let rowVal = ds_odrWrkPathStepDetail.getRowPosition();

                let newRow = ds_odrWrkPathStepDetail.insertRow(rowVal + 1);

                ds_odrWrkPathStepDetail.setCellData(newRow, "odrWrkStpSeq", v_seq + v_add);
                ds_odrWrkPathStepDetail.setCellData(newRow, "odrNo", ds_odrWrkPathStepDetail.getCellData(rowVal, "odrNo"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "cntrSeq", ds_odrWrkPathStepDetail.getCellData(rowVal, "cntrSeq"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "odrWrkPathSeq", ds_odrWrkPathStepDetail.getCellData(rowVal, "odrWrkPathSeq"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "wrkPlClsCd", ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStpCd", ds_ctrtWrkPathStpDetail.getCellData(i, "wrkStpCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "dptWrkPlCd", ds_ctrtWrkPathStpDetail.getCellData(i, "dptWrkPlCd"));
                if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(newRow, "wrkPlClsCd"))) {
                    ds_odrWrkPathStepDetail.setCellData(newRow, "dptWrkPlNm", ds_ctrtWrkPathStpDetail.getCellData(i, "dptWrkPlNm"));
                } else {
                    ds_odrWrkPathStepDetail.setCellData(newRow, "dptWrkPlNm", "");
                }
                ds_odrWrkPathStepDetail.setCellData(newRow, "arvWrkPlCd", ds_ctrtWrkPathStpDetail.getCellData(i, "arvWrkPlCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "arvWrkPlNm", ds_ctrtWrkPathStpDetail.getCellData(i, "arvWrkPlNm"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "selpchItemCd", ds_ctrtWrkPathStpDetail.getCellData(i, "selpchItemCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "selpchItemNm", ds_ctrtWrkPathStpDetail.getCellData(i, "selpchItemNm"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "wrkLobranCd", ds_ctrtWrkPathStpDetail.getCellData(i, "wrkLobranCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "wrkLobranNm", ds_ctrtWrkPathStpDetail.getCellData(i, "wrkLobranNm"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "internalSellLodeptCd", ds_ctrtWrkPathStpDetail.getCellData(i, "internalSellLodeptCd"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "internalSellLodeptNm", ds_ctrtWrkPathStpDetail.getCellData(i, "internalSellLodeptNm"));
                ds_odrWrkPathStepDetail.setCellData(newRow, "fullEmptyClsCd", ds_ctrtWrkPathStpDetail.getCellData(i, "fullEmptyClsCd"));

                if (v_flg == 1) {
                    scwin.f_railstepDetail();
                }
                ////작업노드/운송모드,시간배분,(SD401도착일시=SD403도착일시), 중간단계삽입되었을때 이후시간단계배분 반영영
                let prewrkStDt = ds_odrWrkPathStepDetail.getCellData(rowVal, "wrkStDt");
                let prewrkStHh = ds_odrWrkPathStepDetail.getCellData(rowVal, "wrkStHh");
                let prewrkEndDt = ds_odrWrkPathStepDetail.getCellData(rowVal, "wrkEndDt");
                let prewrkEndHh = ds_odrWrkPathStepDetail.getCellData(rowVal, "wrkEndHh");

                ////작업노드/운송모드,시간배분,(SD401도착일시=SD403도착일시)
                if ($c.gus.cfIsNull(ds_ctrtWrkPathStpDetail.getCellData(i, "wrkPlClsCd"))) {
                    //운송모드 //FROM
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStDt", prewrkEndDt);
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStHh", prewrkEndHh);
                    //TO
                    nowwrkEndMh = Number(prewrkEndHh.substring(0, 2)) * 60 + Number(prewrkEndHh.substring(2, 4)) + 60;
                    if (nowwrkEndMh >= 1440) {
                        Dday = 1;
                        DHours = "00";
                        DMinits = String(nowwrkEndMh - 1440);
                        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt",String(scwin.addDay(prewrkEndDt.substring(0, 4), prewrkEndDt.substring(4, 6), prewrkEndDt.substring(6, 8), Dday)));
                    } else {
                        Dday = 0;
                        DHours = String(Math.floor(nowwrkEndMh / 60));
                        DMinits = String(nowwrkEndMh % 60);
                        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt", prewrkEndDt);
                    }
                    if (Number(DHours) <= 9) {
                        DHours = "0" + String(Number(DHours));
                        if (parseInt(DMinits) <= 9) {
                            if (parseInt(DMinits) != 0) {
                                DMinits = "0" + String(parseInt(DMinits));
                            } else {
                                DMinits = "00";
                            }
                        }
                    } else {
                        if (parseInt(DMinits) <= 9) {
                            if (parseInt(DMinits) != 0) {
                                DMinits = "0" + String(parseInt(DMinits));
                            } else {
                                DMinits = "00";
                            }
                        }
                    }
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndHh", DHours + DMinits);

                } else {
                    //작업 노느 //FROM
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStDt", prewrkEndDt);
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkStHh", prewrkEndHh);
                    //TO
                    nowwrkEndMh = Number(prewrkEndHh.substring(0, 2)) * 60 + Number(prewrkEndHh.substring(2, 4)) + 20;

                    if (nowwrkEndMh >= 1440) {
                        Dday = 1;
                        DHours = "00";
                        DMinits = String(nowwrkEndMh - 1440);

                        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt", String(scwin.addDay(prewrkEndDt.substring(0, 4), prewrkEndDt.substring(4, 6), prewrkEndDt.substring(6, 8), Dday)));
                    } else {
                        Dday = 0;
                        DHours = String(Math.floor(nowwrkEndMh / 60));
                        DMinits = String(nowwrkEndMh % 60);
                        ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndDt", prewrkEndDt);
                    }
                    if (Number(DHours) <= 9) {
                        DHours = "0" + String(Number(DHours));
                        if (parseInt(DMinits) <= 9) {
                            if (parseInt(DMinits) != 0) {
                                DMinits = "0" + String(parseInt(DMinits));
                            } else {
                                DMinits = "00";
                            }
                        }
                    } else {
                        if (parseInt(DMinits) <= 9) {
                            if (parseInt(DMinits) != 0) {
                                DMinits = "0" + String(parseInt(DMinits));
                            } else {
                                DMinits = "00";
                            }
                        }
                    }
                    ds_odrWrkPathStepDetail.setCellData(newRow, "wrkEndHh", DHours + DMinits);

                }
                // 중간 단계 삽입인 경우에는  시간 배분반 다시 돌긴다.
                ds_odrWrkPathStepDetail.setRowPosition(newRow);
                gr_odrWrkPathStepDetail.setFocusedCell(newRow, "odrWrkStpSeq");
                scwin.distribute();
            }
        }
    }
    gr_odrWrkPathStepDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowCount()-1, "odrWrkStpSeq");

    //여기다 경로 체크를 해준다.
    ds_odrCntrWrkPath.setCellData(ds_odrCntrWrkPath.getRowPosition(), "chk", 1);
    scwin.f_setodrWrkPathStepTemplete();
}



scwin.distribute = function () {
    ////작업노드/운송모드,시간배분,(SD401도착일시=SD403도착일시), 중간단계삽입되었을때 이후시간단계배분 반영영
    let j = ds_odrWrkPathStepDetail.getRowPosition();
    for (i = j; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {

        let prewrkStDt = (ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkStDt"));
        let prewrkStHh = (ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkStHh"));
        let prewrkEndDt = (ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkEndDt"));
        let prewrkEndHh = (ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkEndHh"));

        ////작업노드/운송모드,시간배분,(SD401도착일시=SD403도착일시)
        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd"))) {
            //운송모드 //FROM
            ds_odrWrkPathStepDetail.setCellData(i, "wrkStDt", prewrkEndDt);
            ds_odrWrkPathStepDetail.setCellData(i, "wrkStHh", prewrkEndHh);
            //TO
            nowwrkEndMh = Number(prewrkEndHh.substring(0, 2)) * 60 + Number(prewrkEndHh.substring(2, 4)) + 60;

            if (nowwrkEndMh >= 1440) {
                Dday = 1;
                DHours = "00";
                DMinits = String(nowwrkEndMh - 1440);
                ds_odrWrkPathStepDetail.setCellData(i, "wrkEndDt", String(scwin.addDay(prewrkEndDt.substring(0, 4), prewrkEndDt.substring(4, 6), prewrkEndDt.substring(6, 8), Dday)));
            } else {
                Dday = 0;
                DHours = String(Math.floor(nowwrkEndMh / 60));
                DMinits = String(nowwrkEndMh % 60);
                ds_odrWrkPathStepDetail.setCellData(i, "wrkEndDt", prewrkEndDt);
            }
            if (Number(DHours) <= 9) {
                DHours = "0" + String(Number(DHours));
                if (parseInt(DMinits) <= 9) {
                    if (parseInt(DMinits) != 0) {
                        DMinits = "0" + String(parseInt(DMinits));
                    } else {
                        DMinits = "00";
                    }
                }
            } else {
                if (parseInt(DMinits) <= 9) {
                    if (parseInt(DMinits) != 0) {
                        DMinits = "0" + String(parseInt(DMinits));
                    } else {
                        DMinits = "00";
                    }
                }
            }
            ds_odrWrkPathStepDetail.setCellData(i, "wrkEndHh", DHours + DMinits);

        } else {
            //작업 노느 //FROM
            ds_odrWrkPathStepDetail.setCellData(i, "wrkStDt", prewrkEndDt);
            ds_odrWrkPathStepDetail.setCellData(i, "wrkStHh", prewrkEndHh);
            //TO
            nowwrkEndMh = Number(prewrkEndHh.substring(0, 2)) * 60 + Number(prewrkEndHh.substring(2, 4)) + 20;
            if (nowwrkEndMh >= 1440) {
                Dday = 1;
                DHours = "00";

                DMinits = String(nowwrkEndMh - 1440);
                ds_odrWrkPathStepDetail.setCellData(i, "wrkEndDt",String(scwin.addDay(prewrkEndDt.substring(0, 4), prewrkEndDt.substring(4, 6), prewrkEndDt.substring(6, 8), Dday)));
            } else {
                Dday = 0;
                DHours = String(Math.floor(nowwrkEndMh / 60));
                DMinits = String(nowwrkEndMh % 60);
                ds_odrWrkPathStepDetail.setCellData(i, "wrkEndDt", prewrkEndDt);
            }
            if (Number(DHours) <= 9) {
                DHours = "0" + String(Number(DHours));
                if (parseInt(DMinits) <= 9) {
                    if (parseInt(DMinits) != 0) {
                        DMinits = "0" + String(parseInt(DMinits));
                    } else {
                        DMinits = "00";
                    }
                }
            } else {
                if (parseInt(DMinits) <= 9) {
                    if (parseInt(DMinits) != 0) {
                        DMinits = "0" + String(parseInt(DMinits));
                    } else {
                        DMinits = "00";
                    }
                }
            }
            ds_odrWrkPathStepDetail.setCellData(i, "wrkEndHh", DHours + DMinits);

        }
        // 중간 단계 삽입인 경우에는  시간 배분반 다시 돌긴다.
    }
}

// 날짜 메서드가 될 함수 구현
scwin.add_date = function (i) {
    scwin.currentDate = this.getDate() + i * 1;  // 현재 날짜에 더해(빼)줄 날짜를 계산
    this.setDate(scwin.currentDate);  // 계산된 날짜로 다시 세팅
}

// 시간 메서드가 될 함수 구현
scwin.add_time = function (i) {
    scwin.currentTime = this.getHours() + i * 1;  // 현재 날짜에 더해(빼)줄 날짜를 계산
    this.setHours(scwin.currentTime);  // 계산된 날짜로 다시 세팅
}


//+n일 구하기
scwin.addDay = function (yyyy, mm, dd, pDay) { // 년, 월, 일, 계산할 일자 (년도는 반드시 4자리로 입력)
    let oDate; // 리턴할 날짜 객체 선언

    dd = dd * 1 + pDay * 1; // 날짜 계산

    mm--; // 월은 0~11 이므로 하나 빼준다
    //let NowDate = new Date().format("YYYYMMDD");
    oDate = new Date(yyyy, mm, dd).format("YYYYMMDD") // 계산된 날짜 객체 생성 (객체에서 자동 계산)

    return oDate;
}


//-------------------------------------------------------------------------
// 선택된 DATASET에 ROW 복사 ( 대상 DataSet, 원본 Row, 대상 Row )
//-------------------------------------------------------------------------
scwin.f_CopyDataRow = function (dataObject, sourceRow, targetRow) {
    let v_odrWrkStpSeq = parseInt(dataObject.getCellData(sourceRow, "odrWrkStpSeq"));
    let v_tempSeq = (parseInt(v_odrWrkStpSeq / 10) * 10);
    let colId = "";

    for (let i = 0; i < dataObject.getTotalCol(); i++) {
        colId = dataObject.getColumnID(i);

        if (colId == "odrWrkStpSeq") {
            dataObject.setCellData(targetRow, colId, parseInt(dataObject.getCellData(sourceRow, colId)) + 1);
        } else if (["arvWrkPlClsCd", "dptWrkPlClsCd", "dptWrkPlClsCdChange", "arvWrkPlClsCdChange"].includes(colId)) {
            dataObject.setCellData(targetRow, colId, " ");
        } else if(colId == "wrkPlClsCd" || colId == "wrkStpCd"
            || colId == "dptWrkPlCd" || colId == "dptWrkPlNm"
            || colId == "arvWrkPlCd" || colId == "arvWrkPlNm"
            || colId == "wrkLobranCd" || colId == "wrkLobranNm"
            || colId == "internalSellLodeptCd" || colId == "internalSellLodeptNm"
            || colId == "bizDomCd" || colId == "completeYn"){
        } else if (colId == "selpchItemCd") {
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
        } else if (colId == "selpchItemNm") {
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
        } else {
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
        }
    }

    // 오더작업단계순번 재정의
    for (let j = 0; j < dataObject.getRowCount(); j++) {
        let v_compSeq = dataObject.getCellData(j, "odrWrkStpSeq") - v_tempSeq;

        if (dataObject.getCellData(j, "odrWrkStpSeq") > v_tempSeq && v_compSeq > 0 && v_compSeq < 10) {
            dataObject.setCellData(j, "odrWrkStpSeq", parseInt(dataObject.getCellData(j - 1, "odrWrkStpSeq")) + 1);
        }
    }
}


//-------------------------------------------------------------------------
// 선택된 오더 유형별 화면 설정을 변경한다.
//-------------------------------------------------------------------------
scwin.f_setDisplayOdrKndCd = function (odrKndCd) {

    switch (odrKndCd) {
        case DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR:   // 컨테이너 수출일반 오더
            break;
        case DsConstants.ODR_KND_CD_IMP_STV_CNTR_ODR:    // 컨테이너 수입하역 오더
        case DsConstants.ODR_KND_CD_EXP_STV_CNTR_ODR:    // 컨테이너 수출하역 오더
            gr_odrCntrWrkPath.setColumnVisible("qty", false);
            gr_odrCntrWrkPath.setColumnVisible("cntrTypCd", false);
            gr_odrCntrWrkPath.setColumnVisible("arvWrkPlNm", false);
            break;
        default:
            gr_odrCntrWrkPath.setColumnVisible("qty", false);
            gr_odrCntrWrkPath.setColumnVisible("cntrTypCd", true);
            gr_odrCntrWrkPath.setColumnVisible("arvWrkPlNm", true);
            break;
    }
}

//-------------------------------------------------------------------------
// 오더작업단계정보를 작업단계 그리드에 설정한다.
//-------------------------------------------------------------------------
//철송작업단계 추가 체크관련  함수입니다.
scwin.f_railstepDetail = function () {
    let v_count = 0;

    scwin.v_last_rail1 = 0;
    scwin.v_last_rail2 = 0;
    scwin.v_last_rail3 = 0;
    scwin.v_last_rail4 = 0;

    for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        // 향후 철송단계가 한경로에 3단계이상 있는경우 여기다 추가 해준다
        if (ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd") == "R") {
            v_count = v_count + 1;
            //출발역
            let kkk;
            if (v_count % 2 == 1) {
                if (scwin.v_last_rail1 == 0) {
                    scwin.v_last_rail1 = i;
                } else {
                    scwin.v_last_rail3 = i;
                }
            }
            //도착역
            if (v_count % 2 == 0) {
                if (scwin.v_last_rail2 == 0) {
                    scwin.v_last_rail2 = i;
                } else {
                    scwin.v_last_rail4 = i;
                }
            }
        }
    }
}


scwin.f_setOdrWrkPathStepToWrkPathStepDetail = function () {
    let v_count = 0;

    scwin.v_last_rail1 = 0;
    scwin.v_last_rail2 = 0;
    scwin.v_last_rail3 = 0;
    scwin.v_last_rail4 = 0;
    scwin.max_step = 0;

    ds_odrWrkPathStepDetail.removeAll();
    $c.gus.cfCopyDataSetHeader(ds_odrWrkPathStep, ds_odrWrkPathStepDetail);
    $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStep, ds_odrWrkPathStepDetail);

    for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        //실적이 있는 min_row,max_row 가지자
        if (ds_odrWrkPathStepDetail.getCellData(i, "transRsltsSeq") != 0
            || !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "transWrkIndictNo"))) {
            if (scwin.min_step > i) {
                scwin.min_step = i - 1;
            }
            if (scwin.max_step < i) {
                scwin.max_step = i + 1;
            }
        }
        // 향후 철송단계가 한경로에 3단계이상 있는경우 여기다 추가 해준다
        if (ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd") == "R") {
            v_count = v_count + 1;
            //출발역
            let kkk;
            if (v_count % 2 == 1) {
                if (scwin.v_last_rail1 == 0) {
                    scwin.v_last_rail1 = i;
                } else {
                    scwin.v_last_rail3 = i;
                }
            }
            //도착역
            if (v_count % 2 == 0) {
                if (scwin.v_last_rail2 == 0) {
                    scwin.v_last_rail2 = i;
                } else {
                    scwin.v_last_rail4 = i;
                }
            }
        }

        if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim())) {    // 작업구분이 운송인 경우 작업장 표시 안함.
            ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlNm", "");
        }

        if (ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") == SdConstants.SELPCH_ITEM_CD_NOSELL
            && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim())) {
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranCd", "");
            ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranNm", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptCd", "");
            ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNm", "");
        }
    }
}



//-------------------------------------------------------------------------
// 작업경로별 작업단계 정보를 저장하여 동일 작업경로 선택시 참조한다.
//-------------------------------------------------------------------------
scwin.f_copyTempDataSet = function () {

    let v_cntrSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "cntrSeq");
    let v_odrWrkPathSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrWrkPathSeq");
    let v_ctrtWrkPathSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtWrkPathSeq");
    // ds_odrWrkPathStepDetailTemp.filter();

    // 선택된 컨테이너 작업경로 정보를 저장
    scwin.f_CopyDataSetOdrCntrWrkPath(ds_odrCntrWrkPath, ds_odrCntrWrkPathTemp);

    ds_odrCntrWrkPathTemp.modifyAllStatus("R");

    if (ds_odrWrkPathStepDetailTemp.getRowCount() > 0) {
        // 선택된 계약작업경로의 작업단계 정보가 존재하는 경우
        // 저장되어 있던 작업단계 정보를 삭제후 복사
        ds_odrWrkPathStepDetailTemp.removeAll();
        scwin.f_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepDetailTemp);
    } else {
        // 작업단계 정보를 복사
        scwin.f_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepDetailTemp);
    }

    ds_odrWrkPathStepDetailTemp.modifyAllStatus("R")
}


//-------------------------------------------------------------------------
// 선택된 컨테이너 작업경로 정보를 임시 데이터셋에 복사한다.
//-------------------------------------------------------------------------
scwin.f_CopyDataSetOdrCntrWrkPath = function (ds1, ds2) {

    let row = ds1.getRowPosition();

    if (ds1.getRowStatus(row) != "D") {    // RowStatus 가 Delete 가 아닌 경우

        ds2.removeAll(); // ds2.ClearAll();
        $c.gus.cfCopyDataSetHeader(ds1, ds2);
        // ds2.AddRow();
        ds2.insertRow()
        for (let j = 0; j < ds1.getTotalCol(); j++) {
            ds2.setCellData(ds2.getRowPosition(), ds1.getColumnID(j), ds1.getCellData(row, ds1.getColumnID(j)));
        }
    }
}


//-------------------------------------------------------------------------
// 임시 저장된 작업단계 정보를 해당 작업경로의 작업단계 정보로 복사한다.
//-------------------------------------------------------------------------
scwin.f_CopyDataSetValue = function (ds1, ds2) {

    let v_cntrSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "cntrSeq");
    let v_odrWrkPathSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrWrkPathSeq");
    let v_ctrtWrkPathSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtWrkPathSeq");
    let v_fullEmptyClsCd = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "fullEmptyClsCd");

    for (let i = 0; i < ds1.getRowCount(); i++) {
        if (ds1.getRowStatus(i) != "D") {  // RowStatus 가 Delete 가 아닌 경우
            let newRow = ds2.insertRow();
            for (let j = 0; j < ds1.getTotalCol(); j++) {
                switch (ds1.getColumnID(j)) {
                    case "cntrSeq":
                        ds2.setCellData(newRow, ds1.getColumnID(j), v_cntrSeq);
                        break;
                    case "odrWrkPathSeq":
                        ds2.setCellData(newRow, ds1.getColumnID(j), v_odrWrkPathSeq);
                        break;
                    case "ctrtWrkPathSeq":
                        ds2.setCellData(newRow, ds1.getColumnID(j), v_ctrtWrkPathSeq);
                        break;
                    case "fullEmptyClsCd":
                        if (scwin.hid_odrKndCd != DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR && scwin.hid_odrKndCd != DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR) {
                            // 수입일반 , 수출일반 오더가 아닌 경우 컨테이너별 F/E 정보를 설정한다.
                            ds2.setCellData(newRow, ds1.getColumnID(j), v_fullEmptyClsCd);
                        }
                        break;
                    default:
                        ds2.setCellData(newRow, ds1.getColumnID(j), ds1.getCellData(i, ds1.getColumnID(j)));
                        break;
                }
            }
        }
    }
}


//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openPopUp(disGubun, '', pVal, 'T', 'T');
    }
}


