//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = async function (disGubun, row, pCode, pName, pClose, pAllSearch) {

    // 선언부
    let rtnList = new Array();  // 공통POP-UP -> 요청화면
    scwin.chkValue = false;
    scwin.row1 = row;

    switch (disGubun) {
        case 1:
            await udc_logisDeptInfo.cfCommonPopUpAsync(scwin.udc_logisDeptInfo1_callBackFunc    // XML상의 SELECT ID
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서
                , null                   // 보여주는 각 컬럼들의 폭
                , null                   // 컬럼중에서 숨기는    컬럼 지정
                , "A,B"                  // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이
                , null                   // 윈도우 위치 Y좌표
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "작업점소,점소코드,점소명"                // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;

        case 2:
            // 작업장 팝업   - 작업단계별 작업장 팝업
            pWrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkPlClsCd").trim();       // 작업구분코드
            pBizDomCd = ds_odrWrkPathStepDetail.getCellData(row, "bizDomCd").trim();// 사업영역코드

            pWhere = pWrkPlClsCd;
            await udc_wrkPlInfo.cfCommonPopUpAsync(scwin.udc_wrkPlInfo_callBackFunc        // XML상의 SELECT ID
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서
                , null                   // 보여주는 각 컬럼들의 폭
                , null                   // 컬럼중에서 숨기는    컬럼 지정
                , pWhere                 // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이
                , null                   // 윈도우 위치 Y좌표
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "작업장,작업장코드,작업장명"               // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 3:

            // 매출귀속 부서 팝업   : 작업점소(물류점소 : 팀[T]+작업장(J)) 팝업       - 물류점소구분코드 : LO120 - 팀(T), 지점(A), 사업소(B), CY(C), CFS(F), 작업장(J)
            pWrkLobranCd = ds_odrWrkPathStepDetail.getCellData(row, "wrkLobranCd");    // 작업점소코드
            pWhere = "T,J";

            udc_logisDeptInfo.cfCommonPopUpAsync(scwin.udc_logisDeptInfo2_callBackFunc        // XML상의 SELECT ID
                , pCode                  // 화면에서의 ??? Code Element의  Value
                , pName                  // 화면에서의 ??? Name Element의  Value
                , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   // Title순서
                , null                   // 보여주는 각 컬럼들의 폭
                , null                   // 컬럼중에서 숨기는    컬럼 지정
                , pWhere                 // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   // POP-UP뛰을때 우도우의   사용자 정의  높이
                , null                   // 윈도우 위치 Y좌표
                , null                   // 윈도우 위치 X좌표
                , null                   // 중복체크여부   ("F")
                , pAllSearch                 // 전체검색허용여부 ("F")
                , "매출귀속부서,부서코드,부서명"              // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        default:
            break;
    }

    return scwin.chkValue;

}

scwin.udc_logisDeptInfo1_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            //return value Assign
            ds_odrWrkPathStepDetail.setCellData(scwin.row1, "wrkLobranCd", rtnList[0]);  //작업점소코드
            ds_odrWrkPathStepDetail.setCellData(scwin.row1, "wrkLobranNm", rtnList[1]);  //작업점소명
        }
        scwin.chkValue = true;
    } else {
        ds_odrWrkPathStepDetail.setCellData(scwin.row1, "wrkLobranCd", "");  //작업점소코드
        ds_odrWrkPathStepDetail.setCellData(scwin.row1, "wrkLobranNm", "");  //작업점소명
    }
};

scwin.udc_wrkPlInfo_callBackFunc = function(rtnList) {
    let row = scwin.row1;
    if (rtnList != null) {
        if (rtnList[0].trim() != "N/A") {
            //return value Assign
            ds_odrWrkPathStepDetail.setCellData(scwin.row1, "dptWrkPlCd", rtnList[0]);   //작업장 코드
            if (!$c.gus.cfIsNull(rtnList[3])) ds_odrWrkPathStepDetail.setCellData(scwin.row1, "bizDomCd", rtnList[3]); //작업장 사업영역코드
            if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(scwin.row1, "wrkPlClsCd").trim()))  // 운송 단계가 아닌경우 작업장명 설정
                ds_odrWrkPathStepDetail.setCellData(scwin.row1, "dptWrkPlNm", rtnList[1]);   //작업장 명

            // 해당 단계의 출발지를 다음 단계의 출발지로 설정 (다음 단계가 운송 단계인 경우)
            if (row > 1 && row < ds_odrWrkPathStepDetail.getRowCount()) {
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(scwin.row1 + 1, "wrkPlClsCd").trim())
                    && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(scwin.row1, "dptWrkPlCd"))) {
                    ds_odrWrkPathStepDetail.setCellData(scwin.row1 + 1, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(scwin.row1, "dptWrkPlCd"));
                }
            }
        }
        scwin.chkValue = true;
    } else {
        ds_odrWrkPathStepDetail.setCellData(scwin.row1, "dptWrkPlCd", "");   //작업장 코드
        ds_odrWrkPathStepDetail.setCellData(scwin.row1, "dptWrkPlNm", "");   //작업장 명
    }
};

