//오더번호검색 팝업열기 ed_odrNo
scwin.f_openPopUpOdrNo = async function () {
    let args = new Array();
    args[0] = ed_cntrNo.getValue().trim(); //컨테이너번호
    args[1] = ""; //오더종류

    // let rtnList = window.showModalDialog('/ds/sd/odrmgnt/odrreg/sd_402_01_31p.jsp?paramTitle=오더검색팝업', 
    // args, 'dialogWidth:820px; dialogHeight:400px; status:No');

    let v_url = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_31p.xml";
    let opts = {
        id: "pupup",
        popupName: "오더검색팝업",
        modal: true,
        type: "browserPopup",
        width: 820,
        height: 400,
        title: "오더검색팝업"
    };

    rtnList = await $c.win.openPopup(v_url, opts, args);

    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            ed_odrNo.setValue(rtnList[0]);  // 오더번호
        }
    }
}

