scwin.f_setodrWrkPathStepTemplete = function () {
    //작업장 이 change 되었을 때 copy dataSet 담는다.
    scwin.org_check_point = 0;
    ds_odrWrkPathStepTemplete.removeAll();
    $c.gus.cfCopyDataSetHeader(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);
    $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);

    for (let row = 0; row < ds_odrWrkPathStepTemplete.getRowCount(); row++) {
        if (!$c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(row, "transWrkIndictNo"))) {
            scwin.org_check_point = scwin.org_check_point + 1;
        }

        // 하차지 수정일때 는 이전에 운송단계가 있으면 운송단계의 TO지역 수정
        if (ds_odrWrkPathStepTemplete.getCellData(row, "dptWrkPlCd") != ds_odrWrkPathStepTemplete.getCellData(row - 1, "arvWrkPlCd")
            && (ds_odrWrkPathStepTemplete.getCellData(row, "wrkStpCd") == "0029" || ds_odrWrkPathStepTemplete.getCellData(row, "wrkStpCd") == "0012"
                || ds_odrWrkPathStepTemplete.getCellData(row, "wrkStpCd") == "0046")) { //하차
            ds_odrWrkPathStepTemplete.setCellData(row - 1, "arvWrkPlCd", ds_odrWrkPathStepTemplete.getCellData(row, "dptWrkPlCd"));
        }
        // 상차지 수정일때 는 이후에 운송단계가 있으면 운송단계의 FROM지역 수정
        if (ds_odrWrkPathStepTemplete.getCellData(row, "dptWrkPlCd") != ds_odrWrkPathStepTemplete.getCellData(row + 1, "dptWrkPlCd")
            && (ds_odrWrkPathStepTemplete.getCellData(row, "wrkStpCd") == "0028" || ds_odrWrkPathStepTemplete.getCellData(row, "wrkStpCd") == "0011"
                || ds_odrWrkPathStepTemplete.getCellData(row, "wrkStpCd") == "0046")) { //하차
            ds_odrWrkPathStepTemplete.setCellData(row + 1, "dptWrkPlCd", ds_odrWrkPathStepTemplete.getCellData(row, "dptWrkPlCd"));
        }
    }

    ds_odrCntrWrkPathTemplete.removeAll();
    $c.gus.cfCopyDataSetHeader(ds_odrCntrWrkPath, ds_odrCntrWrkPathTemplete);

    ds_odrCntrWrkPathTemplete.insertRow();

    ds_odrCntrWrkPathTemplete.setCellData(0, "odrNo", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrNo"));
    ds_odrCntrWrkPathTemplete.setCellData(0, "cntrSeq", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "cntrSeq"));
    ds_odrCntrWrkPathTemplete.setCellData(0, "odrWrkPathSeq", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrWrkPathSeq"));
    ds_odrCntrWrkPathTemplete.setCellData(0, "ctrtNo", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtNo"));
    ds_odrCntrWrkPathTemplete.setCellData(0, "ctrtWrkPathSeq", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtWrkPathSeq"));
    ds_odrCntrWrkPathTemplete.setCellData(0, "dptWrkPlCd", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "dptWrkPlCd"));
    ds_odrCntrWrkPathTemplete.setCellData(0, "arvWrkPlCd", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "arvWrkPlCd"));
}


