scwin.applyRowColor = function() {
    let rowCount = ds_odrWrkPathStepDetail.getRowCount();

    for (let i = 0; i < rowCount; i++) {
        // 1. 현재 행, 이전 행, 다음 행의 값 가져오기
        let currentVal = ds_odrWrkPathStepDetail.getCellData(i, "transRsltsSeq");
        let nextVal = "";
        let prevVal = "";

        if (i + 1 < rowCount) {
            nextVal = ds_odrWrkPathStepDetail.getCellData(i + 1, "transRsltsSeq");
        }

        if (i - 1 >= 0) {
            prevVal = ds_odrWrkPathStepDetail.getCellData(i - 1, "transRsltsSeq");
        }

        let isCurrentTarget = (!$c.gus.cfIsNull(currentVal) && currentVal != "0");
        let isNextTarget = (!$c.gus.cfIsNull(nextVal) && nextVal != "0");
        let isPrevTarget = (!$c.gus.cfIsNull(prevVal) && prevVal != "0");

        // 3. 셋 중 하나라도 조건에 만족하면 해당 행(Row)의 배경색을 오렌지로 변경
        if (isCurrentTarget || isNextTarget || isPrevTarget) {
            gr_odrWrkPathStepDetail.setCellBackgroundColor(i, "odrWrkStpSeq", "orange");
            gr_odrWrkPathStepDetail.setCellBackgroundColor(i, "wrkPlClsCd", "orange");
            gr_odrWrkPathStepDetail.setCellBackgroundColor(i, "wrkStpCd", "orange");
            gr_odrWrkPathStepDetail.setCellBackgroundColor(i, "selpchItemNm", "orange");
            gr_odrWrkPathStepDetail.setCellBackgroundColor(i, "dptWrkPlNm", "orange");
            gr_odrWrkPathStepDetail.setCellBackgroundColor(i, "wrkLobranCd", "orange");
            gr_odrWrkPathStepDetail.setCellBackgroundColor(i, "wrkLobranNm", "orange");
            gr_odrWrkPathStepDetail.setCellBackgroundColor(i, "internalSellLodeptNm", "orange");
        }
    }
};

