// 컨테이너 변경시 해당 작업경로에 대한 작업단계 조회
// for=ds_odrCntrWrkPath event=OnRowPosChanged(row)
scwin.ds_odrCntrWrkPath_onrowpositionchange = async function (info) {
    let row = info.newRowIndex;
    let rowData = ds_odrCntrWrkPath.getRowJSON(row);

    if (ds_odrCntrWrkPath.getCellData(row, "ctrtWrkPathSeq") > 0 && scwin.f_isOnLoadCompleted()) {
        // 작업단계 검색 조건 설정
        ds_searchWrkStep.set("odrNo", rowData["odrNo"]);
        ds_searchWrkStep.set("cntrSeq", rowData["cntrSeq"]);
        ds_searchWrkStep.set("odrWrkPathSeq", rowData["odrWrkPathSeq"]);
        ds_searchWrkStep.set("ctrtNo", rowData["ctrtNo"]);
        ds_searchWrkStep.set("ctrtWrkPathSeq", rowData["ctrtWrkPathSeq"]);
        ds_searchWrkStep.set("cntrNo", rowData["cntrNo"]);

        if (ed_cntrNo.getValue() != "") {
            ds_searchWrkStep.set("cntrNo", ed_cntrNo.getValue());
        }

        await scwin.f_RetrieveWorkStep();
        let rowCnt = ds_odrWrkPathStepDetail.getRowCount();
        totalRows2.setValue(rowCnt);
    }
    scwin.applyRowColor();

    gr_odrWrkPathStepDetail.focus();
    gr_odrWrkPathStepDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowCount()-1, "odrWrkStpSeq");
    ds_odrWrkPathStepDetail.modifyAllStatus("R")
    gr_odrCntrWrkPath.focus();
};

scwin.ds_odrWrkPathStepDetail_OnFilter = function(row) {
    let v_odrNo = "";
    let v_cntrSeq = 0;
    let v_wrkPathSeq = 0;
    let v_odrWrkPathSeq = 0;
    let v_ctrtWrkPathSeq = 0;
    let chkFilter = scwin.hid_chkUseFilter;

    ds_LkStepNo.removeColumnFilterAll();
    ds_odrWrkPathStepDetail.removeColumnFilterAll();

    if(chkFilter){
        // Filter 적용을 위한 값 
        if(ds_odrCntrWrkPath.getRowPosition() >= 0){
            v_odrNo = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrNo");
            v_cntrSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "cntrSeq");
            v_odrWrkPathSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrWrkPathSeq");
            v_ctrtWrkPathSeq = ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtWrkPathSeq");
        }

        // 필터 적용
        $c.data.dataListFilter(ds_odrWrkPathStepDetail, "odrNo == '"+v_odrNo+"'" 
        + " && cntrSeq == '" + v_cntrSeq + "'"
        + " && odrWrkPathSeq == '" + v_odrWrkPathSeq + "'"
        + " && ctrtWrkPathSeq == '" + v_ctrtWrkPathSeq + "'");
    }
}

