                    await $c.gus.cfAlertMsg("출발작업장이  달라  선택할수 없습니다.");
                    return false;
                }
                //도착작업장  체크
                if (ds_odrCntrWrkPath.getCellData(rowIndex, "arvWrkPlCd") == ds_odrCntrWrkPathTemplete.getCellData(0, "arvWrkPlCd")) {

                } else {
                    ds_odrCntrWrkPath.setCellData(ds_odrCntrWrkPath.getRowPosition(), "chk", 0);
                    await $c.gus.cfAlertMsg("출발작업장이  달라  선택할수 없습니다.");
                    return false;
                }
            }
            break;
    }
    scwin.org2_check_point = scwin.org2_check_point + 1;
};

scwin.gr_odrWrkPathStepDetail_focusOut = async function (rowIndex, colId, columnIndex, value) {
    scwin.row = rowIndex;
    let row = rowIndex;
    let colid = colId;
    let pName = value;
    let pOrgName = scwin.oldValue;
    scwin.chkPopup = true;

    switch (colid) {
        case "wrkLobranNm":
            if (pName != "" && pName != pOrgName) scwin.chkPopup = scwin.f_openCommPopUpGrid(1, row, pName, pName, 'T', 'T');
            else if (pName == "")   ds_odrWrkPathStepDetail.setCellData(row,"wrkLobranCd", "");

            //작업장 이 change 되었을 때 copy dataSet 담는다.
            scwin.org_check_point = 0;
            ds_odrWrkPathStepTemplete.removeAll();
            $c.gus.cfCopyDataSetHeader(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);
            $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);

            for (let j=0; j<ds_odrWrkPathStepTemplete.getRowCount(); j++) {
                 if(!$c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(j, "transWrkIndictNo"))){
                    scwin.org_check_point = scwin.org_check_point+1;
                 }
            }

            ds_odrCntrWrkPathTemplete.removeAll();
            $c.gus.cfCopyDataSetHeader(ds_odrCntrWrkPath, ds_odrCntrWrkPathTemplete);

            ds_odrCntrWrkPathTemplete.insertRow();
            ds_odrCntrWrkPathTemplete.setCellData(0, "odrNo", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrNo"));
            ds_odrCntrWrkPathTemplete.setCellData(0, "cntrSeq", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "cntrSeq"));
            ds_odrCntrWrkPathTemplete.setCellData(0, "odrWrkPathSeq", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "odrWrkPathSeq"));
            ds_odrCntrWrkPathTemplete.setCellData(0, "ctrtNo", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtNo"));
            ds_odrCntrWrkPathTemplete.setCellData(0, "ctrtWrkPathSeq", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "ctrtWrkPathSeq"));
            ds_odrCntrWrkPathTemplete.setCellData(0, "dptWrkPlCd", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "dptWrkPlCd"));
            ds_odrCntrWrkPathTemplete.setCellData(0, "arvWrkPlCd", ds_odrCntrWrkPath.getCellData(ds_odrCntrWrkPath.getRowPosition(), "arvWrkPlCd"));

            break;
        case "dptWrkPlNm":
            if (pName != "" && pName != pOrgName)  {
                scwin.chkPopup = await scwin.f_openCommPopUpGrid(2, row, pName, pName, 'T', 'T');
            }
            else if (pName == "")   {
                ds_odrWrkPathStepDetail.setCellData(row,"dptWrkPlCd", "");
            }

            ds_odrWrkPathStepDetail.setCellData(row,"copCoClntNo","U");
            if( ds_odrWrkPathStepDetail.getCellData(row,"wrkPlClsCd") == ds_odrWrkPathStepDetail.getCellData(row+1,"wrkPlClsCd")
              && ds_odrWrkPathStepDetail.getCellData(row,"wrkStpCd") == "0029" //하차
              && ds_odrWrkPathStepDetail.getCellData(row+1,"wrkStpCd") == "0028" //상차
              ){
                ds_odrWrkPathStepDetail.setCellData(row+1,"dptWrkPlNm",ds_odrWrkPathStepDetail.getCellData(row,"dptWrkPlNm"));
                ds_odrWrkPathStepDetail.setCellData(row+1,"dptWrkPlCd",ds_odrWrkPathStepDetail.getCellData(row,"dptWrkPlCd"));
                ds_odrWrkPathStepDetail.setCellData(row+1,"internalSellLodeptCd",ds_odrWrkPathStepDetail.getCellData(row,"internalSellLodeptCd"));
                ds_odrWrkPathStepDetail.setCellData(row+1,"internalSellLodeptNm",ds_odrWrkPathStepDetail.getCellData(row,"internalSellLodeptNm"));
                ds_odrWrkPathStepDetail.setCellData(row+1,"copCoClntNo","U");
            }

