              && ds_odrWrkPathStepDetail.getCellData(row,"wrkStpCd") == "0029" //하차
              && ds_odrWrkPathStepDetail.getCellData(row+1,"wrkStpCd") == "0028" //상차
              && ds_odrWrkPathStepDetail.getCellData(row+2,"wrkStpCd") == "0001" //셔틀
              ){
                ds_odrWrkPathStepDetail.setCellData(row+1,"dptWrkPlNm", ds_odrWrkPathStepDetail.getCellData(row,"dptWrkPlNm"));
                ds_odrWrkPathStepDetail.setCellData(row+1,"dptWrkPlCd",ds_odrWrkPathStepDetail.getCellData(row,"dptWrkPlCd"));
                ds_odrWrkPathStepDetail.setCellData(row+1,"internalSellLodeptCd",ds_odrWrkPathStepDetail.getCellData(row,"internalSellLodeptCd"));
                ds_odrWrkPathStepDetail.setCellData(row+1,"internalSellLodeptNm",ds_odrWrkPathStepDetail.getCellData(row,"internalSellLodeptNm"));
