            }

            if( ds_odrWrkPathStepDetail.getCellData(row,"wrkPlClsCd") == ds_odrWrkPathStepDetail.getCellData(row+1,"wrkPlClsCd")
              && ds_odrWrkPathStepDetail.getCellData(row,"wrkStpCd") == "0029" //하차
