            $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);

            for (let j=0; j<ds_odrWrkPathStepTemplete.getRowCount(); j++) {
                 if(!$c.gus.cfIsNull(ds_odrWrkPathStepTemplete.getCellData(j, "transWrkIndictNo"))){
                    scwin.org_check_point = scwin.org_check_point+1;
                 }
            }

            break;
        case "internalSellLodeptNm":
            if (pName != "" && pName != pOrgName)  scwin.chkPopup = await scwin.f_openCommPopUpGrid(3, row, pName, pName, 'T', 'T');
            else if (pName == "")   ds_odrWrkPathStepDetail.setCellData(row,"internalSellLodeptCd", "");

            //작업장 이 change 되었을 때 copy dataSet 담는다.
