scwin.gr_odrWrkPathStepDetail_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if(columnId == "selpchItemNm" || columnId == "dptWrkPlNm" || columnId == "wrkLobranNm" || columnId == "internalSellLodeptNm" ) {
        scwin.oldValue = ds_odrWrkPathStepDetail.getCellData(rowIndex, columnId);
    }

    if(columnId == "wrkStpCd" && btn_edit.getDisabled() && !btn_save.getDisabled()){
        scwin.ds_LkStepNo_OnFilter(rowIndex);
    }

    if (scwin.max_step < rowIndex) {

    } else {
        if (scwin.max_step == 0) {

        } else {
            await $c.win.alert("실적이 발생되지 않은  부분만 선 택 할수 있습니다.");
        }
    }
    let chk_su = 0;
    for (let i = 0; i < ds_odrCntrWrkPath.getRowCount(); i++) {
