scwin.gr_odrWrkPathStepDetail_oneditend = function (rowIndex, columnIndex, value) {
    let colid = gr_odrWrkPathStepDetail.getColumnID(columnIndex);
    switch (colid) {
        case "wrkPlClsCd":  // 작업장 구분
             scwin.ds_LkStepNo_OnFilter();
        case "wrkStpCd":    // 작업단계
            ds_odrWrkPathStepTemplete.removeAll();
            $c.gus.cfCopyDataSetHeader(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);
            $c.gus.cf_CopyDataSetValue(ds_odrWrkPathStepDetail, ds_odrWrkPathStepTemplete);
        default:
            break;
    }
};

scwin.ds_LkStepNo_OnFilter = function(row) {
    if(ds_odrWrkPathStepDetail.getRowCount() > 0){
        let v_wrkPlClsCd = ds_odrWrkPathStepDetail.getCellData(ds_odrWrkPathStepDetail.getRowPosition(), "wrkPlClsCd").trim();
        let v_fltrCd1 = "";

        // 작업장구분 코드로 FLTR_CD_1 값 조회	
        if(v_wrkPlClsCd != ""){
            for(let i = 0 ; i < ds_wrkPlClsCd.getRowCount(); i++){
                if(v_wrkPlClsCd == ds_wrkPlClsCd.getCellData(i,"cd")){
                    v_fltrCd1 = ds_wrkPlClsCd.getCellData(i,"fltrCd1");
                }
            }
        }

        let hidVal = "";
        if (ds_odrWrkPathStepDetail.getRowCount() > 0) {
            if(v_fltrCd1 == "02"){  // 하역 (작업단계코드 : 01)
                hidVal = "01";
            } else if(v_fltrCd1 != "02" && v_fltrCd1 != ""){    // 본관,포장 (작업단계코드 : 03,04)
                hidVal = "03";
            } else {    // 운송 (작업단계코드 : 02)
                hidVal = "02";
            }

            ds_LkStepNo.removeColumnFilterAll();
            $c.data.dataListFilter(ds_LkStepNo, "topWrkStpCd == '"+hidVal+"'");
        }
    }
}

