scwin.ds_odrctrtWrkPath_OnFilter = function(row) {
    let v_gubun = lc_gubun.getValue();
    let v_arv = ed_wrkPlCd.getValue();
    let chkFilter = scwin.hid_chkUseFilter;

    ds_odrctrtWrkPath.removeColumnFilterAll();

    if(chkFilter) {
        // 필터 적용
        $c.data.dataListFilter(ds_odrctrtWrkPath, "gubun == '"+v_gubun+"'");
    }
}

