scwin.gr_odrCntrWrkPath_onheaderclick = async function (headerId) {
    let bCheck = gr_odrCntrWrkPath.getHeaderValue("chk_header");  // 체크 여부
    if (ds_odrWrkPathStepTemplete.getRowCount() == 0) {
        await $c.win.alert("작업경로 변경사항이 없습니다.");
        scwin.org2_check_point = 0;
        return false;

    } else {
        if (headerId == "chk_header") { // Colid -> headerId
            if (bCheck == "1") {
                for (let i = 0; i < ds_odrCntrWrkPath.getRowCount(); i++) {
                    let check_point = 0;

                    for (let j = 0; j < ds_odrWrkPathStepChg.getRowCount(); j++) {
                        if (ds_odrCntrWrkPath.getCellData(i, "odrNo") == ds_odrWrkPathStepChg.getCellData(j, "odrNo") &&
                            ds_odrCntrWrkPath.getCellData(i, "cntrSeq") == ds_odrWrkPathStepChg.getCellData(j, "cntrSeq")) {

                            if (!$c.gus.cfIsNull(ds_odrWrkPathStepChg.getCellData(j, "transWrkIndictNo"))) {
                                check_point = check_point + 1;
                            }
                        }
                    }

                    if (scwin.org_check_point != check_point) {
                        await $c.win.alert("작업단계 진행정도가 다른니다.");
                        ds_odrCntrWrkPath.setCellData(i, "chk", 0);
                        return false;
                    }
                    ds_odrCntrWrkPath.setCellData(i, "chk", 1);
                }
            } else {
                for (let i = 0; i < ds_odrCntrWrkPath.getRowCount(); i++) {
                    ds_odrCntrWrkPath.setCellData(i, "chk", 0);
                }
            }
        }
    }
};


scwin.lc_odrSearchGubun_onviewchange = function (info) {
    let v_index = lc_odrSearchGubun.getValue();
    if (v_index == 0) {
        // 오더기간으로 검색시 바인딩 정보 수정
        ed_odrNo.hide(); // cf_ShowObject([lay_odrDt]); // 오더기간 조회조건
        udc_fromToCalendar1.show(); // 출발일자 조회조건 // lay_odrNo -> udc_fromToCalendar1
        // 오더기간, 출발일자 검색조건 초기화
        ed_reqFromDt.setValue(scwin.vCurDate);  // 조회기준일
        ed_reqToDt.setValue(scwin.vCurDate);  // 조회기준일
        $c.gus.cfInitObjects(ed_odrNo);
    } else {
        // 출발일자로 검색시 바인딩 정보 수정
        udc_fromToCalendar1.hide();// 오더기간 조회조건 // lay_odrNo -> udc_fromToCalendar1 
        ed_odrNo.show(); // cf_ShowObject([lay_odrNo]); // 출발일자 조회조건
        // 오더기간, 출발일자 검색조건 초기화
        ed_reqFromDt.setValue("");
        ed_reqToDt.setValue("");
    }
};

