scwin.gr_odrWrkPathStepDetail_onafteredit = function (rowIndex, columnIndex, value,info) {
    let colId = gr_odrWrkPathStepDetail.getColumnID(columnIndex);
    if(colId == "wrkPlClsCd") {
        scwin.gr_odrWrkPathStepDetail_oneditend(rowIndex, columnIndex, value);
    }

    if(colId == "selpchItemNm" || colId == "dptWrkPlNm" || colId == "wrkLobranNm" || colId == "internalSellLodeptNm" ) {
        if (info.type === 'mousedown') {
            return false;
        }
        scwin.gr_odrWrkPathStepDetail_focusOut(rowIndex, colId, columnIndex, value);
    }
};
